'use client'

import React, { useState } from 'react';
import { useBudget } from '@/context/BudgetContext';
import { User, Lock, ArrowRight, Loader2, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { GoogleLogin } from '@react-oauth/google';
import { useRouter } from 'next/navigation';

export default function Login() {
    const { login, loginWithGoogle } = useBudget();
    const router = useRouter();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPass, setShowPass] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');
        try {
            const success = await login(username, password);
            if (success) {
                router.push('/dashboard');
            } else {
                setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
            }
        } catch (err: any) {
            setError(`เกิดข้อผิดพลาด: ${err.message || 'กรุณาลองใหม่อีกครั้ง'}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen w-full flex" style={{ background: 'var(--surface-page)' }}>

            {/* ── LEFT: KTB-style Branding Panel ── */}
            <div className="hidden lg:flex lg:w-[48%] flex-col justify-between relative overflow-hidden"
                style={{
                    background: 'linear-gradient(160deg, #004A24 0%, #007A3B 35%, #00A651 75%, #2BAD6B 100%)',
                }}>

                {/* Subtle wave decoration */}
                <div className="absolute bottom-0 left-0 right-0 h-64 opacity-10"
                    style={{
                        backgroundImage: 'radial-gradient(ellipse 120% 80% at 50% 120%, white 0%, transparent 70%)',
                    }} />
                <div className="absolute top-0 right-0 w-64 h-64 opacity-[0.06]"
                    style={{
                        backgroundImage: 'radial-gradient(circle, white 1px, transparent 1px)',
                        backgroundSize: '28px 28px',
                    }} />

                <div className="relative z-10 flex flex-col justify-between h-full px-12 py-10">
                    {/* Top section */}
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white/15 flex items-center justify-center">
                            <span className="text-white text-lg font-bold">฿</span>
                        </div>
                        <div>
                            <p className="text-white text-sm font-bold leading-tight">DCC Budget</p>
                            <p className="text-white/50 text-[10px] font-medium tracking-wider uppercase">Management Platform</p>
                        </div>
                    </div>

                    {/* Center content */}
                    <div className="space-y-6 max-w-sm">
                        <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/10 border border-white/15">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-300 animate-pulse" />
                            <span className="text-[11px] font-semibold text-white/80 tracking-wide">ระบบออนไลน์</span>
                        </div>

                        <h1 className="text-[38px] font-bold text-white leading-tight tracking-tight">
                            บริหารงบประมาณ<br />
                            <span className="text-emerald-300">อย่างชาญฉลาด</span>
                        </h1>
                        <p className="text-[14px] text-white/60 leading-relaxed">
                            ยกระดับการบริหารงบประมาณด้วยความโปร่งใส รวดเร็ว
                            และแม่นยำ บน Digital Platform ที่ทันสมัย
                        </p>

                        {/* Feature stats */}
                        <div className="grid grid-cols-2 gap-3 pt-2">
                            {[
                                { emoji: '🔒', label: '100%', sub: 'Data Security' },
                                { emoji: '⚡', label: 'Real-time', sub: 'Budget Tracking' },
                                { emoji: '📊', label: 'Smart', sub: 'Analytics' },
                                { emoji: '✅', label: 'Auto', sub: 'Approval Flow' },
                            ].map((feat) => (
                                <div key={feat.label}
                                    className="flex items-center gap-2.5 px-4 py-2.5 rounded-xl bg-white/08 border border-white/10 backdrop-blur-sm">
                                    <span className="text-lg">{feat.emoji}</span>
                                    <div>
                                        <p className="text-sm font-bold text-white leading-none">{feat.label}</p>
                                        <p className="text-[10px] text-white/45 mt-0.5">{feat.sub}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom */}
                    <p className="text-[10px] text-white/20 tracking-[0.18em] uppercase">
                        Secured by DCC Platform • v3.0
                    </p>
                </div>
            </div>

            {/* ── RIGHT: Login Form ── */}
            <div className="flex-1 flex flex-col items-center justify-center px-6 py-10 bg-white">
                <div className="w-full max-w-[400px]">

                    {/* Mobile logo */}
                    <div className="lg:hidden mb-6">
                        <div className="w-10 h-10 rounded-xl flex items-center justify-center text-white text-lg font-bold"
                            style={{ background: 'var(--color-primary-500)' }}>฿</div>
                    </div>

                    {/* Form header */}
                    <div className="mb-8">
                        <h2 className="text-[26px] font-bold mb-1" style={{ color: 'var(--text-primary)' }}>
                            เข้าสู่ระบบ
                        </h2>
                        <p className="text-sm" style={{ color: 'var(--text-secondary)' }}>
                            ป้อนข้อมูลของคุณเพื่อเข้าสู่ระบบบริหารงบประมาณ
                        </p>
                    </div>

                    {/* Error */}
                    {error && (
                        <div className="mb-5 flex items-center gap-2.5 px-4 py-3 rounded-xl text-sm"
                            style={{ background: 'var(--accent-red-light)', border: '1px solid #FEB2B2' }}>
                            <AlertCircle className="w-4 h-4 text-red-500 flex-shrink-0" />
                            <span className="font-medium text-red-600">{error}</span>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-4">

                        {/* Username */}
                        <div>
                            <label className="block text-sm font-semibold mb-1.5"
                                style={{ color: 'var(--text-primary)' }}>
                                ชื่อผู้ใช้งาน
                            </label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                    <User className="w-4 h-4" style={{ color: 'var(--text-tertiary)' }} />
                                </div>
                                <input
                                    type="text" required value={username}
                                    onChange={(e) => setUsername(e.target.value)}
                                    className="ktb-input pl-11"
                                    placeholder="ระบุชื่อผู้ใช้งาน"
                                    disabled={isLoading}
                                    autoComplete="username"
                                />
                            </div>
                        </div>

                        {/* Password */}
                        <div>
                            <div className="flex items-center justify-between mb-1.5">
                                <label className="text-sm font-semibold" style={{ color: 'var(--text-primary)' }}>
                                    รหัสผ่าน
                                </label>
                                <span className="text-xs font-medium cursor-pointer"
                                    style={{ color: 'var(--color-primary-600)' }}>
                                    ลืมรหัสผ่าน?
                                </span>
                            </div>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                    <Lock className="w-4 h-4" style={{ color: 'var(--text-tertiary)' }} />
                                </div>
                                <input
                                    type={showPass ? 'text' : 'password'} required value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="ktb-input pl-11 pr-11"
                                    placeholder="••••••••"
                                    disabled={isLoading}
                                    autoComplete="current-password"
                                />
                                <button type="button" onClick={() => setShowPass(!showPass)}
                                    className="absolute inset-y-0 right-0 pr-4 flex items-center"
                                    style={{ color: 'var(--text-tertiary)' }}>
                                    {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                </button>
                            </div>
                        </div>

                        {/* Sign in button */}
                        <button type="submit" disabled={isLoading} className="btn-primary w-full mt-2">
                            {isLoading ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                            ) : (
                                <>เข้าสู่ระบบ <ArrowRight className="w-4 h-4" /></>
                            )}
                        </button>

                        {/* Divider */}
                        <div className="flex items-center gap-3 py-1">
                            <div className="flex-1 h-px" style={{ background: 'var(--border-default)' }} />
                            <span className="text-[11px] font-medium tracking-wider uppercase"
                                style={{ color: 'var(--text-tertiary)' }}>หรือ</span>
                            <div className="flex-1 h-px" style={{ background: 'var(--border-default)' }} />
                        </div>

                        {/* Google Login */}
                        <div className="flex justify-center">
                            <GoogleLogin
                                onSuccess={async (credentialResponse) => {
                                    if (credentialResponse.credential) {
                                        setIsLoading(true);
                                        try {
                                            const success = await loginWithGoogle(credentialResponse.credential);
                                            if (success) router.push('/dashboard');
                                        } catch { setError('Google Sign-In Error'); }
                                        finally { setIsLoading(false); }
                                    }
                                }}
                                onError={() => setError('Google Sign-In Failed')}
                                shape="pill" theme="outline" size="large"
                                text="signin_with"
                            />
                        </div>
                    </form>

                    {/* Footer */}
                    <p className="mt-8 text-center text-sm" style={{ color: 'var(--text-tertiary)' }}>
                        ไม่มีบัญชีผู้ใช้งาน?{' '}
                        <span className="font-semibold cursor-pointer hover:underline"
                            style={{ color: 'var(--color-primary-600)' }}>
                            ติดต่อผู้ดูแลระบบ
                        </span>
                    </p>
                </div>
            </div>
        </div>
    );
}
